 1→import type { MittwaldCliToolHandler } from '../../../../../types/mittwald/conversation.js';
 2→import { formatToolResponse } from '../../../../../utils/format-tool-response.js';
 3→import { deleteMysqlUser, LibraryError } from '@mittwald-mcp/cli-core';
 4→import { sessionManager } from '../../../../../server/session-manager.js';
 5→import { getCurrentSessionId } from '../../../../../utils/execution-context.js';
 6→import { logger } from '../../../../../utils/logger.js';
 7→
 8→interface MittwaldDatabaseMysqlUserDeleteArgs {
 9→  userId: string;
10→  confirm?: boolean;
11→  force?: boolean;
12→  quiet?: boolean;
13→}
14→
15→export const handleDatabaseMysqlUserDeleteCli: MittwaldCliToolHandler<MittwaldDatabaseMysqlUserDeleteArgs> = async (
16→  args,
17→  sessionId,
18→) => {
19→  const effectiveSessionId = sessionId || getCurrentSessionId();
20→
21→  if (!effectiveSessionId) {
22→    return formatToolResponse('error', 'Session ID required');
23→  }
24→
25→  if (!args.userId) {
26→    return formatToolResponse('error', 'User ID is required to delete a MySQL user.');
27→  }
28→
29→  if (args.confirm !== true) {
30→    return formatToolResponse(
31→      'error',
32→      'MySQL user deletion requires confirm=true. This operation is destructive and cannot be undone.'
33→    );
34→  }
35→
36→  const session = await sessionManager.getSession(effectiveSessionId);
37→  if (!session?.mittwaldAccessToken) {
38→    return formatToolResponse('error', 'No Mittwald access token found in session. Please authenticate first.');
39→  }
40→
41→  logger.warn('[DatabaseMysqlUserDelete] Destructive operation attempted', {
42→    mysqlUserId: args.userId,
43→    force: Boolean(args.force),
44→    sessionId: effectiveSessionId,
45→  });
46→
47→  try {
48→    const result = await deleteMysqlUser({
49→      userId: args.userId,
50→      apiToken: session.mittwaldAccessToken,
51→    });
52→
53→    return formatToolResponse(
54→      'success',
55→      `Successfully deleted MySQL user ${args.userId}.`,
56→      {
57→        userId: args.userId,
58→        deleted: true,
59→      },
60→      {
61→        durationMs: result.durationMs,
62→      }
63→    );
64→  } catch (error) {
65→    if (error instanceof LibraryError) {
66→      return formatToolResponse('error', error.message, {
67→        code: error.code,
68→        details: error.details,
69→      });
70→    }
71→
72→    logger.error('[WP06] Unexpected error in database mysql user delete handler', { error });
73→    return formatToolResponse('error', `Failed to delete MySQL user: ${error instanceof Error ? error.message : String(error)}`);
74→  }
75→};
